const yaml = require('js-yaml');
const raw = $input.item.json.stdout || '';
const doc = yaml.load(raw) || { vendors: [] };
const now = Date.now();
const soon = (doc.vendors || []).map(v => {
  const r = v.renewal_date ? new Date(v.renewal_date).getTime() : null;
  const d = r ? Math.floor((r - now) / 86400000) : null;
  return { ...v, daysToRenewal: d };
}).filter(v => v.daysToRenewal !== null && v.daysToRenewal >= 0 && v.daysToRenewal <= 7);
if (soon.length === 0) return [];
const lines = soon.map(v => `• ${v.vendor} renews in ${v.daysToRenewal}d ($${(v.monthly_cost||0)}/mo)`).join('\n');
return [{ json: {
  priority: 'P1',
  source: 'vendor-renewal-watch',
  message: `${soon.length} vendor renewal${soon.length>1?'s':''} ≤7d:\n${lines}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/maintain/vendors'
}}];
